109	    const parsedPatches = parsePatchFiles(
110	      normalizedPatch,
111	      buildPatchCacheKey(normalizedPatch, cacheScope),
112	    );
113	    const files = parsedPatches.flatMap((parsedPatch) => parsedPatch.files);
114	    if (files.length > 0) {
115	      return { kind: "files", files };
116	    }
117	
118	    return {
119	      kind: "raw",
120	      text: normalizedPatch,
121	      reason: "Unsupported diff format. Showing raw patch.",
122	    };
123	  } catch {
124	    return {
125	      kind: "raw",
126	      text: normalizedPatch,
127	      reason: "Failed to parse patch. Showing raw patch.",
128	    };
