275	
276	.chat-markdown ul ul {
277	  list-style-type: circle;
278	}
279	
280	.chat-markdown ul ul ul {
281	  list-style-type: square;
282	}
283	
284	.chat-markdown ol ol {
285	  list-style-type: lower-alpha;
286	}
287	
288	.chat-markdown ol ol ol {
289	  list-style-type: lower-roman;
290	}
291	
292	.chat-markdown li + li {
293	  margin-top: 0.25rem;
