295	
296	.chat-markdown a {
297	  color: var(--info-foreground);
298	  text-decoration: underline;
299	  text-decoration-color: color-mix(in srgb, var(--info-foreground) 40%, transparent);
300	}
301	
302	.chat-markdown a:hover {
303	  opacity: 0.8;
304	}
305	
306	.chat-markdown blockquote {
307	  border-left: 2px solid var(--border);
308	  padding-left: 0.8rem;
309	  color: var(--muted-foreground);
310	}
311	
312	.chat-markdown :not(pre) > code {
313	  border: 1px solid var(--border);
314	  border-radius: 0.375rem;
315	  background: var(--muted);
316	  padding: 0.1rem 0.35rem;
317	  color: var(--foreground);
318	  font-size: 0.75rem;
319	}
320	
321	.chat-markdown pre {
322	  max-width: 100%;
323	  overflow-x: auto;
324	  border: 1px solid var(--border);
325	  border-radius: 0.75rem;
326	  background: var(--muted);
327	  padding: 0.8rem 0.9rem;
328	}
329	
330	.chat-markdown pre code {
331	  border: none;
332	  background: transparent;
333	  padding: 0;
334	  line-height: 1.5;
335	  font-size: 0.875rem;
336	}
337	
338	.chat-markdown .chat-markdown-codeblock {
339	  position: relative;
340	  margin: 0.65rem 0;
341	}
342	
343	.chat-markdown .chat-markdown-codeblock pre {
344	  margin: 0;
345	}
346	
347	.chat-markdown .chat-markdown-copy-button {
348	  position: absolute;
349	  top: 0.5rem;
350	  right: 0.5rem;
351	  z-index: 1;
352	  display: inline-flex;
353	  align-items: center;
354	  justify-content: center;
355	  height: 1.5rem;
356	  width: 1.5rem;
357	  border-radius: 0.375rem;
358	  border: 1px solid var(--border);
