import type { ThemeColors, ThemeDefinition } from "@t3tools/contracts";
import { getThemeColors } from "@t3tools/shared/theme";

import { type ThemeSelection, useTheme } from "../hooks/useTheme";
import { cn } from "~/lib/utils";

// ---------------------------------------------------------------------------
// Options (system + built-in themes)
// ---------------------------------------------------------------------------

interface ThemeOption {
  value: ThemeSelection;
  label: string;
  description: string;
  colors: ThemeColors | null;
}

function buildOptions(themes: readonly ThemeDefinition[]): readonly ThemeOption[] {
  return [
    {
      value: "system",
      label: "System",
      description: "Match your OS appearance setting.",
      colors: null,
    },
    ...themes.map((t) => ({
      value: t.id as ThemeSelection,
      label: t.label,
      description:
        t.id === "t3-light"
          ? "A clean, bright workspace."
          : t.id === "t3-dark"
            ? "Easy on the eyes for long sessions."
            : "Deep blue-tinted dark variant.",
      colors: getThemeColors(t.id),
    })),
  ];
}

// ---------------------------------------------------------------------------
// Swatch preview
// ---------------------------------------------------------------------------

function ThemeSwatch({ colors }: { colors: ThemeColors }) {
  const swatches = [
    { color: colors.background, label: "bg" },
    { color: colors.sidebar, label: "sidebar" },
    { color: colors.primary, label: "primary" },
    { color: colors.accent, label: "accent" },
    { color: colors.foreground, label: "fg" },
  ];

  return (
    <div className="flex gap-1" aria-hidden="true">
      {swatches.map((s) => (
        <span
          key={s.label}
          className="size-4 rounded-sm border border-border/60"
          style={{ backgroundColor: s.color }}
          title={s.label}
        />
      ))}
    </div>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { theme, setTheme, themes, resolvedThemeId } = useTheme();

  const options = buildOptions(themes);

  return (
    <div>
      <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
        {options.map((option) => {
          const selected = theme === option.value;
          return (
            <button
              key={option.value}
              type="button"
              role="radio"
              aria-checked={selected}
              className={cn(
                "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
                selected
                  ? "border-primary/60 bg-primary/8 text-foreground"
                  : "border-border bg-background text-muted-foreground hover:bg-accent",
              )}
              onClick={() => setTheme(option.value)}
            >
              <span className="flex flex-col gap-1">
                <span className="flex items-center gap-2">
                  <span className="text-sm font-medium">{option.label}</span>
                  {option.colors && <ThemeSwatch colors={option.colors} />}
                </span>
                <span className="text-xs">{option.description}</span>
              </span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Selected
                </span>
              ) : null}
            </button>
          );
        })}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme: <span className="font-medium text-foreground">{resolvedThemeId}</span>
      </p>
    </div>
  );
}

