export const ThemeMode = Schema.Literal("light", "dark");
export type ThemeMode = typeof ThemeMode.Type;

// ---------------------------------------------------------------------------
// Built-in theme metadata
// ---------------------------------------------------------------------------

export const BUILT_IN_THEMES = [
  { id: "t3-light", label: "T3 Light", mode: "light" as const },
  { id: "t3-dark", label: "T3 Dark", mode: "dark" as const },
  { id: "t3-midnight", label: "T3 Midnight", mode: "dark" as const },
] as const;

export const ThemeId = Schema.Literal(...BUILT_IN_THEMES.map((t) => t.id));
export type ThemeId = typeof ThemeId.Type;

// ---------------------------------------------------------------------------
// Theme color tokens
// ---------------------------------------------------------------------------

export const ThemeColors = Schema.Struct({
  // Core semantic tokens
  background: Schema.String,
  foreground: Schema.String,
  primary: Schema.String,
  primaryForeground: Schema.String,
  secondary: Schema.String,
  secondaryForeground: Schema.String,
  muted: Schema.String,
  mutedForeground: Schema.String,
  accent: Schema.String,
  accentForeground: Schema.String,
  card: Schema.String,
  cardForeground: Schema.String,
  popover: Schema.String,
  popoverForeground: Schema.String,
  border: Schema.String,
  input: Schema.String,
  ring: Schema.String,

  // Status tokens
  destructive: Schema.String,
  destructiveForeground: Schema.String,
  info: Schema.String,
  infoForeground: Schema.String,
  success: Schema.String,
  successForeground: Schema.String,
  warning: Schema.String,
  warningForeground: Schema.String,

  // Area-specific tokens
  sidebar: Schema.String,
  sidebarForeground: Schema.String,
  editor: Schema.String,
  editorForeground: Schema.String,
  terminal: Schema.String,
  terminalForeground: Schema.String,
  statusBar: Schema.String,
  statusBarForeground: Schema.String,
});
export type ThemeColors = typeof ThemeColors.Type;

// ---------------------------------------------------------------------------
// Full theme definition
// ---------------------------------------------------------------------------

export const ThemeDefinition = Schema.Struct({
  id: ThemeId,
  label: Schema.String,
  mode: ThemeMode,
  colors: ThemeColors,
});
export type ThemeDefinition = typeof ThemeDefinition.Type;

