import { createContext, useCallback, useContext, useEffect, useMemo, useSyncExternalStore } from "react";
import type { ThemeColors, ThemeId } from "@t3tools/contracts";
import { BUILT_IN_THEMES } from "@t3tools/contracts";
import {
  getThemeDefinition,
  THEME_COLOR_VAR_MAP,
  THEME_DEFINITIONS,
} from "@t3tools/shared/theme";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type ThemeSelection = ThemeId | "system";

type ThemeSnapshot = {
  selection: ThemeSelection;
  systemDark: boolean;
};

type ThemeContextValue = {
  /** Raw user selection ("system" or a named theme id) */
  theme: ThemeSelection;
  /** Resolved theme id after evaluating system preference */
  resolvedThemeId: ThemeId;
  /** Resolved base mode — backward compatible with old consumers */
  resolvedTheme: "light" | "dark";
  /** Active color palette */
  colors: ThemeColors;
  /** Update the stored theme selection */
  setTheme: (next: ThemeSelection) => void;
  /** All available theme definitions */
  themes: readonly ThemeDefinition[];
};

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

const VALID_SELECTIONS = new Set<string>([
  "system",
  ...BUILT_IN_THEMES.map((t) => t.id),
]);

// ---------------------------------------------------------------------------
// Module-level external store (flash-free, runs before React renders)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): ThemeSelection {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw !== null && VALID_SELECTIONS.has(raw)) return raw as ThemeSelection;
  // Migrate old "light"/"dark" values gracefully
  return "system";
}

function resolveThemeId(selection: ThemeSelection, systemDark: boolean): ThemeId {
  if (selection !== "system") return selection;
  return systemDark ? "t3-dark" : "t3-light";
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------

function applyTheme(selection: ThemeSelection, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const systemDark = getSystemDark();
  const themeId = resolveThemeId(selection, systemDark);
  const definition = getThemeDefinition(themeId);
  const colors = definition.colors;

  // Toggle dark class for Tailwind @variant dark
  document.documentElement.classList.toggle("dark", definition.mode === "dark");

  // Set color-scheme for native UA styling
  document.documentElement.style.setProperty("color-scheme", definition.mode);

  // Apply all color tokens as CSS custom properties
  const varMap = THEME_COLOR_VAR_MAP;
  for (const key of Object.keys(varMap) as Array<keyof ThemeColors>) {
    document.documentElement.style.setProperty(varMap[key], colors[key]);
  }

  // Set data attribute for optional CSS selectors
  document.documentElement.setAttribute("data-theme", themeId);

  if (suppressTransitions) {
    // Force reflow so no-transitions takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

// ---------------------------------------------------------------------------
// useSyncExternalStore plumbing
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const selection = getStored();
  const systemDark = selection === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.selection === selection &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { selection, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const mq = window.matchMedia(MEDIA_QUERY);
  const handleMediaChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleMediaChange);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleMediaChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// React Context
// ---------------------------------------------------------------------------

const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const selection = snapshot.selection;

  const resolvedThemeId = resolveThemeId(selection, snapshot.systemDark);
  const definition = getThemeDefinition(resolvedThemeId);

  const setTheme = useCallback((next: ThemeSelection) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(selection);
  }, [selection]);

  const value = useMemo<ThemeContextValue>(
    () => ({
      theme: selection,
      resolvedThemeId,
      resolvedTheme: definition.mode,
      colors: definition.colors,
      setTheme,
      themes: THEME_DEFINITIONS,
    }),
    [selection, resolvedThemeId, definition, setTheme],
  );

  return <ThemeContext value={value}>{children}</ThemeContext>;
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used within a <ThemeProvider>");
  }
  return ctx;
}
